// ハローワールド — 最初のプログラム
//
// このアプリでは、左のレッスンを選ぶと中央のエディターにコードが表示されます。
// 右上の「▶ 実行」を押すと、このコードがその場で実行され、
// 右のペインに実行結果（標準出力）が表示されます。
//
// まずはそのまま実行してみましょう。次に "Hello, Gopherjuku!" の部分を
// 好きな文章に書き換えて、もう一度実行してみてください。
package main

import "fmt"

func main() {
	// fmt.Println は文字列を 1 行出力します（末尾に自動で改行が付きます）。
	fmt.Println("Hello, Gopherjuku!")

	// Printf は書式を指定して出力します。%d は整数、\n は改行を表します。
	for i := 1; i <= 3; i++ {
		fmt.Printf("%d 回目のこんにちは\n", i)
	}
}

// 変数と型
//
// Go の変数宣言と基本型を見ていきます。値を書き換えて実行し、
// 出力がどう変わるか試してみてください。
package main

import "fmt"

func main() {
	// var で宣言。初期値を省くと「ゼロ値」（int は 0、string は ""）になる。
	var age int
	var name string = "Gopher"
	fmt.Println("age(ゼロ値):", age, "/ name:", name)

	// := は型推論付きの短い宣言（関数の中でだけ使える）。
	height := 172.5 // float64 と推論される
	active := true  // bool
	fmt.Printf("height=%.1f active=%v\n", height, active)

	// 主な基本型
	var i int = -42
	var f float64 = 3.14
	var s string = "文字列"
	var r rune = 'あ' // rune は Unicode コードポイント（int32 の別名）
	var b byte = 'A'  // byte は uint8 の別名
	fmt.Println("int/float/string:", i, f, s)
	fmt.Printf("rune %c=%d, byte %c=%d\n", r, r, b, b)

	// 型変換は必ず明示的に書く（暗黙の変換は無い）。
	n := 10
	x := float64(n) / 3
	fmt.Printf("%d / 3 = %.3f\n", n, x)
}

// 定数と iota
//
// const で定数を宣言します。iota を使うと連番の定数を簡潔に定義できます。
package main

import "fmt"

// 単純な定数
const Pi = 3.14159
const Greeting = "こんにちは"

// iota は const ブロック内で 0 から始まり、行ごとに 1 増える。
const (
	Sunday = iota // 0
	Monday        // 1
	Tuesday       // 2
	Wednesday     // 3
)

// iota を式に使うと、ビットフラグや単位も簡潔に書ける。
const (
	_  = iota             // 0 は捨てる
	KB = 1 << (10 * iota) // 1 << 10
	MB                    // 1 << 20
	GB                    // 1 << 30
)

func main() {
	fmt.Println(Greeting, "Pi =", Pi)
	fmt.Println("曜日:", Sunday, Monday, Tuesday, Wednesday)
	fmt.Println("KB, MB, GB:", KB, MB, GB)
}

// 演算子
//
// 算術・比較・論理・ビット演算の基本を確認します。
package main

import "fmt"

func main() {
	a, b := 17, 5

	// 算術演算：/ は整数どうしだと整数除算、% は剰余。
	fmt.Println("和 差 積:", a+b, a-b, a*b)
	fmt.Println("商 余り:", a/b, a%b)

	// 比較演算：結果は bool。
	fmt.Println("a>b, a==b:", a > b, a == b)

	// 論理演算：&&（かつ）, ||（または）, !（否定）。
	t, f := true, false
	fmt.Println("&& || !:", t && f, t || f, !t)

	// ビット演算：& | ^ << >>
	x, y := 0b1100, 0b1010
	fmt.Printf("AND=%04b OR=%04b XOR=%04b\n", x&y, x|y, x^y)
	fmt.Printf("左シフト 1<<4 = %d\n", 1<<4)
}

// 制御構文（if・for・switch）
//
// Go の分岐とループはとてもシンプルです。ループは for だけ。
package main

import "fmt"

func main() {
	// if：条件に丸括弧は不要。初期化文付きの if も書ける。
	if n := 7; n%2 == 0 {
		fmt.Println(n, "は偶数")
	} else {
		fmt.Println(n, "は奇数")
	}

	// for その1：カウンタ付きの基本形。
	sum := 0
	for i := 1; i <= 5; i++ {
		sum += i
	}
	fmt.Println("1..5 の合計:", sum)

	// for その2：条件だけ書けば while 相当。
	i := 1
	for i < 100 {
		i *= 2
	}
	fmt.Println("100 を超える最小の 2 の累乗:", i)

	// for その3：range でスライスを反復（添字と値を取り出す）。
	for idx, v := range []string{"a", "b", "c"} {
		fmt.Printf("[%d]=%s ", idx, v)
	}
	fmt.Println()

	// switch：break は不要。条件を書かない switch は if-else の連鎖に便利。
	for _, n := range []int{1, 2, 3} {
		switch {
		case n < 2:
			fmt.Println(n, "→ 小")
		case n < 3:
			fmt.Println(n, "→ 中")
		default:
			fmt.Println(n, "→ 大")
		}
	}
}

// 関数
//
// Go の関数は「複数の戻り値」「可変長引数」「名前付き戻り値」を持てます。
package main

import "fmt"

// 複数の戻り値。エラーを 2 つ目に返すのが Go の定石。
func divide(a, b int) (int, error) {
	if b == 0 {
		return 0, fmt.Errorf("0 では割れません")
	}
	return a / b, nil
}

// 可変長引数（...int）。呼び出し側は任意個の引数を渡せる。
func sum(nums ...int) int {
	total := 0
	for _, n := range nums {
		total += n
	}
	return total
}

// 名前付き戻り値。return だけで名前付きの値が返る。
func split(total int) (a, b int) {
	a = total * 4 / 9
	b = total - a
	return
}

func main() {
	q, err := divide(10, 3)
	fmt.Println("10/3 =", q, "err:", err)

	_, err = divide(1, 0)
	fmt.Println("1/0 err:", err)

	fmt.Println("合計:", sum(1, 2, 3, 4, 5))

	x, y := split(18)
	fmt.Println("split(18) =", x, y)
}

// クロージャ
//
// 関数は値として扱えます。関数が外側の変数を「捕まえて」保持したものがクロージャです。
package main

import "fmt"

// 呼ぶたびに 1 増える「カウンタ」を返す。count は各クロージャに固有。
func counter() func() int {
	count := 0
	return func() int {
		count++ // 外側の count を捕まえて更新し続ける
		return count
	}
}

func main() {
	// 関数を変数に入れて使える。
	double := func(n int) int { return n * 2 }
	fmt.Println("double(21) =", double(21))

	// counter() が返すクロージャは、それぞれ独立した count を持つ。
	c1 := counter()
	c2 := counter()
	fmt.Println("c1:", c1(), c1(), c1()) // 1 2 3
	fmt.Println("c2:", c2())             // 1（c1 とは別）
}

// 配列とスライス
//
// 配列は固定長、スライスは可変長。実務ではほぼスライスを使います。
package main

import "fmt"

func main() {
	// 配列：長さが型の一部（[3]int と [4]int は別の型）。
	var arr [3]int
	arr[0], arr[1], arr[2] = 10, 20, 30
	fmt.Println("配列:", arr, "長さ:", len(arr))

	// スライス：可変長。append で要素を追加できる。
	s := []int{1, 2, 3}
	s = append(s, 4, 5)
	fmt.Println("スライス:", s, "len:", len(s), "cap:", cap(s))

	// スライス式 s[low:high]（high は含まない）。
	fmt.Println("s[1:3]:", s[1:3])

	// make で長さ・容量を指定して作る。
	buf := make([]string, 0, 3)
	for _, w := range []string{"go", "is", "fun"} {
		buf = append(buf, w)
	}
	fmt.Println("buf:", buf)

	// スライスは参照的：元と一部を共有する点に注意。
	a := []int{1, 2, 3}
	b := a[:2]
	b[0] = 99
	fmt.Println("共有の例 a:", a, "b:", b) // a[0] も 99 になる
}

// マップ
//
// マップはキーと値の対応表（連想配列）です。
package main

import "fmt"

func main() {
	// リテラルで初期化。
	age := map[string]int{
		"Alice": 30,
		"Bob":   25,
	}

	// 追加・更新・参照。
	age["Carol"] = 28
	fmt.Println("Alice の年齢:", age["Alice"])

	// カンマ ok 記法：キーの有無を確認できる。
	if v, ok := age["Dave"]; ok {
		fmt.Println("Dave:", v)
	} else {
		fmt.Println("Dave は未登録")
	}

	// 削除。
	delete(age, "Bob")

	// fmt はマップをキー順にそろえて出力する（反復順は本来ランダム）。
	fmt.Println("現在のマップ:", age)
	fmt.Println("人数:", len(age))
}

// 構造体
//
// 構造体は複数の値をひとまとめにした型です。
package main

import "fmt"

type Point struct {
	X, Y int
}

type Person struct {
	Name string
	Age  int
	Home Point // 構造体は入れ子にできる
}

func main() {
	// フィールド名を指定した初期化（推奨）。
	p := Person{
		Name: "Alice",
		Age:  30,
		Home: Point{X: 1, Y: 2},
	}

	// フィールドへのアクセス・更新。
	p.Age++
	fmt.Println("名前:", p.Name, "年齢:", p.Age)
	fmt.Println("家の座標:", p.Home.X, p.Home.Y)

	// %+v はフィールド名付きで構造体を出力する。
	fmt.Printf("%+v\n", p)

	// ポインタ経由で更新すると元の値が変わる。
	move(&p.Home)
	fmt.Println("移動後:", p.Home)
}

func move(pt *Point) {
	pt.X += 10
	pt.Y += 10
}

// メソッド
//
// メソッドは特定の型に結び付いた関数です。レシーバに「値」を使うか
// 「ポインタ」を使うかで、元の値を変更できるかが変わります。
package main

import "fmt"

type Counter struct {
	count int
}

// 値レシーバ：コピーに対して働くので、元の値は変わらない（読み取り向き）。
func (c Counter) Value() int {
	return c.count
}

// ポインタレシーバ：元の値を変更できる（更新向き）。
func (c *Counter) Increment() {
	c.count++
}

func main() {
	c := Counter{}

	// ポインタレシーバのメソッドは、変数に対してそのまま呼べる（自動で &c になる）。
	c.Increment()
	c.Increment()
	c.Increment()

	fmt.Println("カウント:", c.Value()) // 3

	// 値レシーバのメソッドは元を変えない例。
	c2 := c
	c2.Increment()
	fmt.Println("c:", c.Value(), "c2:", c2.Value()) // 3 4
}

// インターフェース
//
// インターフェースは「メソッドの集合」を表す型です。ある型がそのメソッドを
// 実装していれば、明示的な宣言なしに自動でインターフェースを満たします
//（構造的部分型）。これが Go の多態性（ポリモーフィズム）の基本です。
package main

import "fmt"

// Shape は「Name() と Area() を持つ」という約束を表すインターフェース。
type Shape interface {
	Name() string
	Area() float64
}

type Rectangle struct{ W, H float64 }
type Circle struct{ R float64 }

// Rectangle と Circle がそれぞれ Name()/Area() を実装する。
// → どちらも自動的に Shape を満たす（"implements" と書く必要はない）。
func (r Rectangle) Name() string  { return "長方形" }
func (r Rectangle) Area() float64 { return r.W * r.H }
func (c Circle) Name() string     { return "円" }
func (c Circle) Area() float64    { return 3.14159 * c.R * c.R }

// 引数を Shape 型にすると、具体的な型を問わず同じように扱える。
func printArea(s Shape) {
	fmt.Printf("%s の面積 = %.2f\n", s.Name(), s.Area())
}

func main() {
	// 異なる型を同じ []Shape にまとめて扱える。
	shapes := []Shape{
		Rectangle{W: 3, H: 4},
		Circle{R: 5},
	}
	for _, s := range shapes {
		printArea(s)
	}
}

// fmt — 書式付き入出力
//
// Println / Printf / Sprintf と、代表的な「動詞（verb）」を確認します。
package main

import "fmt"

type Point struct{ X, Y int }

func main() {
	// Println：スペース区切りで出力して改行。
	fmt.Println("値を並べる:", 1, "two", 3.0, true)

	p := Point{X: 1, Y: 2}

	// 代表的な verb
	fmt.Printf("%%v  値      : %v\n", p)
	fmt.Printf("%%+v フィールド名付き: %+v\n", p)
	fmt.Printf("%%d 整数 / %%b 2進 / %%x 16進: %d %b %x\n", 255, 255, 255)
	fmt.Printf("%%s 文字列 / %%q 引用符付き: %s %q\n", "go", "go")
	fmt.Printf("%%f 小数 / %%.2f 桁指定: %f %.2f\n", 3.14159, 3.14159)
	fmt.Printf("%%T 型: %T %T\n", 42, "hi")

	// Sprintf：出力せず文字列として組み立てる。
	msg := fmt.Sprintf("(%d, %d)", p.X, p.Y)
	fmt.Println("Sprintf の結果:", msg)
}

// strings — 文字列操作
//
// 文字列の検索・置換・分割・連結などをまとめて提供する定番パッケージ。
package main

import (
	"fmt"
	"strings"
)

func main() {
	s := "Hello, Gopher"

	fmt.Println("大文字:", strings.ToUpper(s))
	fmt.Println("含む(Go)?:", strings.Contains(s, "Go"))
	fmt.Println("置換:", strings.ReplaceAll(s, "o", "0"))
	fmt.Println("接頭辞(Hello)?:", strings.HasPrefix(s, "Hello"))

	// 分割と連結
	parts := strings.Split("a,b,c", ",")
	fmt.Printf("分割: %v（%d 個）\n", parts, len(parts))
	fmt.Println("連結:", strings.Join([]string{"x", "y", "z"}, "-"))

	// 前後の空白を除去
	fmt.Printf("トリム前後: %q\n", strings.TrimSpace("  padded  "))

	// Builder は連結を効率よく行う（+ の繰り返しより速い）。
	var b strings.Builder
	for i := 0; i < 3; i++ {
		b.WriteString("go")
	}
	fmt.Println("Builder:", b.String())
}

// strconv — 文字列と数値の変換
//
// 文字列 ↔ 数値・真偽値の変換を行います。
package main

import (
	"fmt"
	"strconv"
)

func main() {
	// 文字列 → 数値。失敗するとエラーを返す。
	n, err := strconv.Atoi("42")
	fmt.Println("Atoi(\"42\"):", n, err)

	_, err = strconv.Atoi("abc")
	fmt.Println("Atoi(\"abc\") のエラー:", err)

	// 数値 → 文字列。
	s := strconv.Itoa(2026)
	fmt.Println("Itoa(2026):", s, "型は string")

	// 浮動小数点・真偽値。
	f, _ := strconv.ParseFloat("3.14", 64)
	b, _ := strconv.ParseBool("true")
	fmt.Println("ParseFloat, ParseBool:", f, b)

	// 基数を指定した変換（2 進数の文字列 → 10 進数）。
	v, _ := strconv.ParseInt("1010", 2, 64)
	fmt.Println("2進 1010 =", v)

	// Quote：エスケープ済みの引用符付き文字列。
	fmt.Println("Quote:", strconv.Quote("行1\n行2"))
}

// sort — 並べ替え
//
// スライスを昇順に並べたり、独自の基準で並べ替えたりできる。
package main

import (
	"fmt"
	"sort"
)

func main() {
	// 基本型は専用関数が用意されている。
	ints := []int{3, 1, 4, 1, 5, 9, 2}
	sort.Ints(ints)
	fmt.Println("昇順:", ints)

	strs := []string{"banana", "apple", "cherry"}
	sort.Strings(strs)
	fmt.Println("辞書順:", strs)

	// sort.Slice なら任意の基準で並べ替えられる（ここでは文字数の降順）。
	words := []string{"go", "gopher", "js", "rust"}
	sort.Slice(words, func(i, j int) bool {
		return len(words[i]) > len(words[j])
	})
	fmt.Println("長さの降順:", words)

	// 昇順に並んだスライスなら二分探索できる。
	pos := sort.SearchInts(ints, 4)
	fmt.Printf("値 4 は位置 %d\n", pos)
}

// time — 日付・時刻・期間
//
// 時刻の生成・加算・差分・整形を行います。
// （実行結果を一定にするため、ここでは固定の日時を使います。）
package main

import (
	"fmt"
	"time"
)

func main() {
	// 固定の日時を作る（time.Now() を使うと実行のたびに変わる）。
	t := time.Date(2026, time.July, 5, 14, 30, 0, 0, time.UTC)

	// Format は「参照時刻 2006-01-02 15:04:05」の並びで書式を指定する（Go 独特）。
	fmt.Println("整形:", t.Format("2006-01-02 15:04:05"))
	fmt.Println("和風:", t.Format("2006年01月02日 15時04分"))

	// Duration（期間）と加算。
	d := 90 * time.Minute
	fmt.Println("90分後:", t.Add(d).Format("15:04"))

	// 2 時刻の差分。
	t2 := time.Date(2026, time.July, 5, 12, 0, 0, 0, time.UTC)
	fmt.Println("差:", t.Sub(t2))

	// 各パーツの取り出し。
	fmt.Printf("年=%d 月=%d 日=%d 時=%d\n", t.Year(), t.Month(), t.Day(), t.Hour())
}

// math と乱数（math / math/rand）
//
// 数学関数と擬似乱数を使います。
// （結果を一定にするため、乱数は固定シードで生成します。）
package main

import (
	"fmt"
	"math"
	"math/rand"
)

func main() {
	// math：定数と関数。
	fmt.Printf("Pi=%.5f  E=%.5f\n", math.Pi, math.E)
	fmt.Printf("Sqrt(2)=%.4f  Pow(2,10)=%.0f\n", math.Sqrt(2), math.Pow(2, 10))
	fmt.Println("Abs(-5), Ceil(2.1), Floor(2.9):", math.Abs(-5), math.Ceil(2.1), math.Floor(2.9))
	fmt.Println("Max, Min:", math.Max(3, 7), math.Min(3, 7))

	// math/rand：固定シードにすると毎回同じ列になる（再現性のため）。
	r := rand.New(rand.NewSource(42))
	fmt.Println("0..99 の乱数:", r.Intn(100), r.Intn(100), r.Intn(100))

	// シャッフルも rand で行える。
	nums := []int{1, 2, 3, 4, 5}
	r.Shuffle(len(nums), func(i, j int) { nums[i], nums[j] = nums[j], nums[i] })
	fmt.Println("シャッフル:", nums)
}

// errors — エラーの生成と判定
//
// エラー値の作り方、独自エラー型、ラップと一致判定を扱います。
package main

import (
	"errors"
	"fmt"
)

// 独自のエラー型：Error() string を実装すれば error として使える。
type ValidationError struct {
	Field string
}

func (e *ValidationError) Error() string {
	return fmt.Sprintf("%s が不正です", e.Field)
}

// 比較の目印になる sentinel エラー。
var ErrEmpty = errors.New("空です")

func validate(name string) error {
	if name == "" {
		// %w でラップすると、元のエラーを保持したまま文脈を付けられる。
		return fmt.Errorf("検証失敗: %w", ErrEmpty)
	}
	return nil
}

func main() {
	// errors.New：シンプルなエラー。
	fmt.Println("New:", errors.New("何かに失敗"))

	// 独自エラー型。Error() の文言が使われる。
	var verr error = &ValidationError{Field: "name"}
	fmt.Println("独自型:", verr)

	// ラップしたエラーは errors.Is で元の sentinel と一致判定できる。
	err := validate("")
	fmt.Println("検証:", err)
	if errors.Is(err, ErrEmpty) {
		fmt.Println("  → 原因は ErrEmpty")
	}
}

// JSON — encoding/json による変換
//
// 構造体と JSON を相互に変換する。Web API や設定ファイルで頻出。
package main

import (
	"encoding/json"
	"fmt"
)

// 構造体タグ `json:"..."` で JSON 側のキー名を指定する。
type User struct {
	Name string   `json:"name"`
	Age  int      `json:"age"`
	Tags []string `json:"tags"`
}

func main() {
	u := User{Name: "Alice", Age: 30, Tags: []string{"go", "web"}}

	// 構造体 → JSON（Marshal）
	b, _ := json.Marshal(u)
	fmt.Println("JSON:", string(b))

	// インデント付きで整形出力
	pretty, _ := json.MarshalIndent(u, "", "  ")
	fmt.Println(string(pretty))

	// JSON → 構造体（Unmarshal）。&v のようにポインタを渡す。
	var v User
	json.Unmarshal([]byte(`{"name":"Bob","age":25,"tags":["cli"]}`), &v)
	fmt.Printf("復元: %+v\n", v)
}

// regexp — 正規表現
//
// パターンによる検索・抽出・置換を行います。
// パターンはバッククォート文字列で書くと、バックスラッシュをそのまま書けて便利です。
package main

import (
	"fmt"
	"regexp"
)

func main() {
	// MustCompile はパターンをコンパイルする（不正なら panic）。
	re := regexp.MustCompile(`\d+`) // 1 個以上の数字

	fmt.Println("数字を含む?:", re.MatchString("abc123"))
	fmt.Println("最初の一致:", re.FindString("a12b345"))
	fmt.Println("全部の一致:", re.FindAllString("a12b345c6", -1))
	fmt.Println("置換:", re.ReplaceAllString("a1b2c3", "#"))

	// グループ () で部分を取り出す。
	mail := regexp.MustCompile(`(\w+)@(\w+)`)
	m := mail.FindStringSubmatch("user@example")
	// m[0]=全体, m[1]=1つ目のグループ, m[2]=2つ目
	fmt.Printf("全体=%s ユーザー=%s ドメイン=%s\n", m[0], m[1], m[2])
}

// 型アサーションと型スイッチ
//
// インターフェース値の「中身の具体的な型」を取り出す方法です。
package main

import "fmt"

func main() {
	// interface{}（= any）はどんな値でも入る。
	var v any = "hello"

	// 型アサーション：v.(T)。カンマ ok 記法で安全に判定できる。
	if s, ok := v.(string); ok {
		fmt.Println("文字列だった。長さ:", len(s))
	}
	if _, ok := v.(int); !ok {
		fmt.Println("int ではない")
	}

	// 型スイッチ：複数の型をまとめて振り分ける。
	for _, x := range []any{42, "go", 3.14, true, []int{1, 2}} {
		fmt.Println(describe(x))
	}
}

func describe(i any) string {
	switch v := i.(type) {
	case int:
		return fmt.Sprintf("int: %d", v)
	case string:
		return fmt.Sprintf("string: %q", v)
	case float64:
		return fmt.Sprintf("float64: %.2f", v)
	default:
		return fmt.Sprintf("その他: %T", v)
	}
}

// 埋め込み（構造体・インターフェースの合成）
//
// Go は継承の代わりに「埋め込み」で機能を再利用します。
// 埋め込んだ型のフィールドやメソッドを、外側の型が自分のものとして使えます。
package main

import "fmt"

type Animal struct {
	Name string
}

func (a Animal) Describe() string {
	return a.Name + " です"
}

// Dog は Animal を「埋め込む」（フィールド名を書かない）。
type Dog struct {
	Animal // 埋め込み
	Breed  string
}

func (d Dog) Bark() string {
	return d.Name + ": ワン!" // 埋め込んだ Animal の Name に直接アクセスできる
}

func main() {
	d := Dog{
		Animal: Animal{Name: "レックス"},
		Breed:  "柴犬",
	}

	// Animal のメソッドを Dog がそのまま持っているように呼べる。
	fmt.Println(d.Describe())
	fmt.Println(d.Bark())
	fmt.Println("犬種:", d.Breed)

	// 埋め込んだフィールドは型名でも参照できる。
	fmt.Println("フルアクセス:", d.Animal.Name)
}

// エラーハンドリング
//
// Go はエラーを「戻り値」で表現します（例外機構ではない）。
// 関数は error を返し、呼び出し側が明示的に確認するのが基本です。
package main

import (
	"errors"
	"fmt"
)

// sentinel エラー：比較の目印としてあらかじめ定義したエラー値。
var ErrNotFound = errors.New("見つかりません")

func find(id int) error {
	if id != 1 {
		// %w でラップすると、元のエラーを保持したまま文脈を追加できる。
		return fmt.Errorf("id=%d の検索に失敗: %w", id, ErrNotFound)
	}
	return nil
}

func main() {
	for _, id := range []int{1, 2} {
		err := find(id)
		if err == nil {
			fmt.Printf("id=%d: OK\n", id)
			continue
		}
		fmt.Printf("id=%d: %v\n", id, err)

		// errors.Is で、ラップされた元エラーと一致するか判定できる。
		if errors.Is(err, ErrNotFound) {
			fmt.Println("  → 原因は ErrNotFound")
		}
	}
}

// defer / panic / recover
//
// defer は「関数を抜けるときに実行」する予約、panic は異常終了、
// recover は panic を捕まえて復帰する仕組みです。
package main

import "fmt"

func main() {
	// defer は後入れ先出し（LIFO）で、関数の最後にまとめて実行される。
	// 後片付け（ファイルを閉じる等）に使う。
	fmt.Println("--- defer の順序 ---")
	demoDefer()

	// panic を recover で捕まえ、エラーとして返す例。
	fmt.Println("--- recover ---")
	err := safeDivide(10, 0)
	fmt.Println("結果:", err)
	fmt.Println("プログラムは継続している")
}

func demoDefer() {
	defer fmt.Println("defer 1（最後に出る）")
	defer fmt.Println("defer 2")
	fmt.Println("本体の処理")
}

// panic しても recover で復帰し、error に変換して返す。
func safeDivide(a, b int) (err error) {
	defer func() {
		if r := recover(); r != nil {
			err = fmt.Errorf("復帰しました: %v", r)
		}
	}()
	if b == 0 {
		panic("ゼロ除算")
	}
	fmt.Println(a / b)
	return nil
}

// goroutine と channel
//
// goroutine は軽量な並行実行の単位、channel はその間でデータを受け渡す通信路です。
// go キーワードで関数を並行に走らせます。
package main

import (
	"fmt"
	"sync"
)

func main() {
	jobs := []int{2, 3, 4}

	// バッファ付き channel に各 goroutine の結果を集める。
	results := make(chan int, len(jobs))

	// WaitGroup で「全 goroutine の完了」を待つ。
	var wg sync.WaitGroup
	for _, n := range jobs {
		wg.Add(1)
		go func(x int) { // x を引数で渡すのが定石（ループ変数の共有を避ける）
			defer wg.Done()
			results <- x * x
		}(n)
	}

	wg.Wait()      // 全部終わるまで待つ
	close(results) // もう送らないので閉じる

	// 閉じた channel は range で最後まで読み切れる。
	sum := 0
	for r := range results {
		sum += r
	}
	// 実行順序は毎回変わるが、合計は一定：4 + 9 + 16 = 29
	fmt.Println("二乗の合計:", sum)
}

// select — 複数チャネルの待ち受け
//
// select は複数の channel 操作のうち、準備ができたものを 1 つ選んで実行します。
// タイムアウトやキャンセルの実装によく使います。
package main

import (
	"fmt"
	"time"
)

func main() {
	fast := make(chan string)
	slow := make(chan string)

	// 2 つの goroutine が別々のタイミングで結果を送る。
	go func() { time.Sleep(20 * time.Millisecond); fast <- "fast の結果" }()
	go func() { time.Sleep(200 * time.Millisecond); slow <- "slow の結果" }()

	// 先に届いた方を受け取る。両方来るまで 2 回ループ。
	for i := 0; i < 2; i++ {
		select {
		case v := <-fast:
			fmt.Println("受信:", v)
		case v := <-slow:
			fmt.Println("受信:", v)
		case <-time.After(time.Second):
			fmt.Println("タイムアウト")
		}
	}

	// time.After を使った単独のタイムアウト例。
	done := make(chan bool)
	go func() { time.Sleep(10 * time.Millisecond); done <- true }()
	select {
	case <-done:
		fmt.Println("処理完了")
	case <-time.After(100 * time.Millisecond):
		fmt.Println("時間切れ")
	}
}

// sync — 並行処理の同期
//
// 複数の goroutine を安全に協調させる道具です。
// WaitGroup（完了待ち）, Mutex（排他制御）, Once（一度だけ実行）を扱います。
package main

import (
	"fmt"
	"sync"
)

func main() {
	// Mutex：複数 goroutine から同じ変数を安全に更新する。
	var mu sync.Mutex
	counter := 0

	// Once：何度呼ばれても初期化を 1 回だけ実行する。
	var once sync.Once

	// WaitGroup：全 goroutine の完了を待つ。
	var wg sync.WaitGroup
	for i := 0; i < 100; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			once.Do(func() { fmt.Println("初期化は一度だけ") })

			mu.Lock() // ロックしてから更新（競合を防ぐ）
			counter++
			mu.Unlock()
		}()
	}
	wg.Wait()

	// Mutex で守ったので、必ず 100 になる。
	fmt.Println("最終カウント:", counter)
}

// ジェネリクス（型パラメータ）
//
// 型パラメータを使うと、型に依存しない汎用的な関数や型を書けます（Go 1.18 以降）。
package main

import "fmt"

// [T any] が型パラメータ。any 制約は「どんな型でも受け取れる」。
// 条件に合う要素だけを残す汎用フィルタ。T は呼び出しから推論される。
func Filter[T any](s []T, keep func(T) bool) []T {
	var r []T
	for _, v := range s {
		if keep(v) {
			r = append(r, v)
		}
	}
	return r
}

// 制約は自分で定義できる。~int は「基底型が int の型すべて」を表す。
type Number interface {
	~int | ~float64
}

// Number を満たす型なら何でも合計できる。
func Sum[T Number](s []T) T {
	var total T
	for _, v := range s {
		total += v
	}
	return total
}

func main() {
	nums := []int{1, 2, 3, 4, 5, 6}

	// 同じ Filter が int にも string にも使える（型ごとに書かなくてよい）。
	evens := Filter(nums, func(n int) bool { return n%2 == 0 })
	fmt.Println("偶数:", evens)

	words := []string{"go", "gopher", "js", "rust"}
	long := Filter(words, func(w string) bool { return len(w) >= 3 })
	fmt.Println("3文字以上:", long)

	// 制約付きジェネリクス。int でも float64 でも同じ Sum で合計できる。
	fmt.Println("int の合計:", Sum(nums))
	fmt.Println("float の合計:", Sum([]float64{1.5, 2.5}))
}
